268	void dh_t::prove(const ecc_point_t& Q, const ecc_point_t& A, const ecc_point_t& B, const bn_t& w, mem_t session_id,
269	                 uint64_t aux) {
270	  ecurve_t curve = Q.get_curve();
271	  const auto& G = curve.generator();
272	  const mod_t& q = curve.order();
273	  bn_t r = curve.get_random_value();
274	
275	  cb_assert(w < q && "w exceeds the order of the curve");
276	
277	  ecc_point_t X = r * G;
278	  ecc_point_t Y = r * Q;
279	
280	  e = crypto::ro::hash_number(G, Q, A, B, X, Y, session_id, aux).mod(q);
281	
282	  MODULO(q) { z = r + e * w; }
283	}
284	
285	error_t dh_t::verify(const ecc_point_t& Q, const ecc_point_t& A, const ecc_point_t& B, mem_t session_id,
286	                     uint64_t aux) const {
287	  error_t rv = UNINITIALIZED_ERROR;
288	
289	  crypto::vartime_scope_t vartime_scope;
290	  ecurve_t curve = Q.get_curve();
291	  if (rv = curve.check(Q)) return coinbase::error(rv, "dh_t::verify: Q is not on the curve");
292	  if (rv = curve.check(A)) return coinbase::error(rv, "dh_t::verify: A is not on the curve");
293	  if (rv = curve.check(B)) return coinbase::error(rv, "dh_t::verify: B is not on the curve");
294	
295	  const auto& G = curve.generator();
296	  const mod_t& q = curve.order();
297	
298	  if (rv = crypto::check_right_open_range(0, e, q)) return rv;
299	  if (rv = crypto::check_right_open_range(0, z, q)) return rv;
300	
301	  ecc_point_t X = z * G - e * A;
302	  ecc_point_t Y = z * Q - e * B;
303	
304	  bn_t e_tag = crypto::ro::hash_number(G, Q, A, B, X, Y, session_id, aux).mod(q);
305	  if (e_tag != e) return coinbase::error(E_CRYPTO, "dh_t::verify: e does not match");
306	  return SUCCESS;
307	}
