7	void uc_elgamal_com_t::prove(const ecc_point_t& Q, const elg_com_t& UV, const bn_t& x, const bn_t& r, mem_t session_id,
8	                             uint64_t aux) {
9	  std::vector<bn_t> r1(params.rho);
10	  std::vector<bn_t> r2(params.rho);
11	  ecurve_t curve = Q.get_curve();
12	  // Public input sanity checks. We hard-fail on infinity to avoid producing proofs for invalid statements.
13	  cb_assert(!Q.is_infinity());
14	  const auto& G = curve.generator();
15	  const mod_t& q = curve.order();
16	  int rho = params.rho;
17	
18	  AB.resize(rho);
19	  e.resize(rho);
20	  z1.resize(rho);
21	  z2.resize(rho);
22	
23	  bn_t z1_tag, z2_tag;
24	  bn_t q_value = bn_t(q);
25	  buf_t common_hash;
26	
27	  fischlin_prove(
28	      params,
29	      // initialize
30	      [&]() {
31	        for (int i = 0; i < rho; i++) {
32	          r1[i] = bn_t::rand(q);
33	          r2[i] = bn_t::rand(q);
34	          AB[i] = elg_com_t::commit(Q, r1[i]).rand(r2[i]);
35	        }
36	        common_hash = crypto::ro::hash_string(G, Q, UV, AB, session_id, aux).bitlen(2 * SEC_P_COM);
37	      },
38	
39	      // response_begin
40	      [&](int i) {
41	        z1_tag = r1[i];
42	        z2_tag = r2[i];
43	      },
44	
45	      // hash
46	      [&](int i, int e_tag) -> uint32_t { return hash32bit_for_zk_fischlin(common_hash, i, e_tag, z1_tag, z2_tag); },
47	
48	      // save
49	      [&](int i, int e_tag) {
50	        e[i] = e_tag;
51	        z1[i] = z1_tag;
52	        z2[i] = z2_tag;
53	      },
54	
55	      // response_next
56	      [&](int e_tag) {
57	        int res = bn_mod_add_fixed_top(z1_tag, z1_tag, x, q_value);
58	        cb_assert(res);
59	        res = bn_mod_add_fixed_top(z2_tag, z2_tag, r, q_value);
60	        cb_assert(res);
61	      });
62	}
