64	error_t uc_elgamal_com_t::verify(const ecc_point_t& Q, const elg_com_t& UV, mem_t session_id, uint64_t aux) const {
65	  error_t rv = UNINITIALIZED_ERROR;
66	  crypto::vartime_scope_t vartime_scope;
67	  if (rv = params.check()) return rv;
68	  int rho = params.rho;
69	  if (int(AB.size()) != rho) return coinbase::error(E_CRYPTO);
70	  if (int(e.size()) != rho) return coinbase::error(E_CRYPTO);
71	  if (int(z1.size()) != rho) return coinbase::error(E_CRYPTO);
72	  if (int(z2.size()) != rho) return coinbase::error(E_CRYPTO);
73	
74	  ecurve_t curve = Q.get_curve();
75	  if (rv = curve.check(Q)) return coinbase::error(rv, "uc_elgamal_com_t::verify: check Q failed");
76	  if (rv = UV.check_curve(curve)) return coinbase::error(rv, "uc_elgamal_com_t::verify: check UV failed");
77	  for (int i = 0; i < rho; i++) {
78	    if (rv = AB[i].check_curve(curve)) return coinbase::error(rv, "uc_elgamal_com_t::verify: check AB failed");
79	  }
80	
81	  const mod_t& q = curve.order();
82	  const auto& G = curve.generator();
83	  uint32_t b_mask = params.b_mask();
84	  buf_t common_hash = crypto::ro::hash_string(G, Q, UV, AB, session_id, aux).bitlen(2 * SEC_P_COM);
85	
86	  bn_t z1_sum = 0;
87	  bn_t z2_sum = 0;
88	  bn_t e_sum = 0;
89	  ecc_point_t A_sum = curve.infinity();
90	  ecc_point_t B_sum = curve.infinity();
91	
92	  for (int i = 0; i < rho; i++) {
93	    if (rv = crypto::check_right_open_range(0, z1[i], q)) return rv;
94	    if (rv = crypto::check_right_open_range(0, z2[i], q)) return rv;
95	
96	    bn_t sigma = bn_t::rand_bitlen(SEC_P_STAT);
97	    MODULO(q) {
98	      z1_sum += sigma * z1[i];
99	      z2_sum += sigma * z2[i];
100	      e_sum += sigma * bn_t(e[i]);
101	    }
102	    A_sum += sigma * AB[i].L;
103	    B_sum += sigma * AB[i].R;
104	
105	    uint32_t h = hash32bit_for_zk_fischlin(common_hash, i, e[i], z1[i], z2[i]) & b_mask;
106	    if (h != 0) return coinbase::error(E_CRYPTO);
107	  }
108	
109	  const ecc_point_t& U = UV.L;
110	  const ecc_point_t& V = UV.R;
111	  if (A_sum != z2_sum * G - e_sum * U) return coinbase::error(E_CRYPTO);
112	  if (B_sum != z2_sum * Q + z1_sum * G - e_sum * V) return coinbase::error(E_CRYPTO);
113	
114	  return SUCCESS;
115	}
