124	error_t elgamal_com_pub_share_equ_t::verify(const ecc_point_t& Q, const ecc_point_t& A, const elg_com_t& B,
125	                                            mem_t session_id, uint64_t aux) const {
126	  crypto::vartime_scope_t vartime_scope;
127	  error_t rv = UNINITIALIZED_ERROR;
128	  ecurve_t curve = Q.get_curve();
129	  if (rv = curve.check(B.R)) return coinbase::error(rv, "elgamal_com_pub_share_equ_t::verify: check B.R failed");
