179	void uc_elgamal_com_mult_private_scalar_t::prove(const ecc_point_t& Q, const elg_com_t& A, const elg_com_t& B,
180	                                                 const bn_t& r, const bn_t& c, mem_t session_id, uint64_t aux) {
181	  std::vector<bn_t> r1(params.rho);
182	  std::vector<bn_t> r2(params.rho);
183	  ecurve_t curve = Q.get_curve();
184	  // Public input sanity checks. We hard-fail on infinity to avoid producing proofs for invalid statements.
185	  cb_assert(!Q.is_infinity());
186	  const mod_t& q = curve.order();
187	  int rho = params.rho;
188	
189	  A1_tag.resize(rho);
190	  A2_tag.resize(rho);
191	  e.resize(rho);
192	  z1.resize(rho);
193	  z2.resize(rho);
194	
195	  bn_t z1_tag, z2_tag;
196	  bn_t q_value = bn_t(q);
197	  buf_t common_hash;
198	
199	  fischlin_prove(
200	      params,
201	      // initialize
202	      [&]() {
203	        const ecc_point_t& A1 = A.L;
204	        const ecc_point_t& A2 = A.R;
205	        for (int i = 0; i < rho; i++) {
206	          r1[i] = bn_t::rand(q);
207	          r2[i] = bn_t::rand(q);
208	          A1_tag[i] = curve.mul_add(r2[i], A1, r1[i]);
209	          A2_tag[i] = ecc_point_t::weighted_sum(r1[i], A2, r2[i], Q);
210	        }
211	        common_hash = crypto::ro::hash_string(Q, A, B, A1_tag, A2_tag, session_id, aux).bitlen(2 * SEC_P_COM);
212	      },
213	
214	      // response_begin
215	      [&](int i) {
216	        z1_tag = r1[i];
217	        z2_tag = r2[i];
218	      },
219	
220	      // hash
221	      [&](int i, int e_tag) -> uint32_t { return hash32bit_for_zk_fischlin(common_hash, i, e_tag, z1_tag, z2_tag); },
222	
223	      // save
224	      [&](int i, int e_tag) {
225	        e[i] = e_tag;
226	        z1[i] = z1_tag;
227	        z2[i] = z2_tag;
228	      },
229	
230	      // response_next
231	      [&](int e_tag) {
232	        int res = bn_mod_add_fixed_top(z1_tag, z1_tag, c, q_value);
233	        cb_assert(res);
234	        res = bn_mod_add_fixed_top(z2_tag, z2_tag, r, q_value);
235	        cb_assert(res);
236	      });
237	}
