27	void dkg_2p_t::step2_p2_to_p1(const bn_t& x2) {
28	  this->x2 = x2;
29	  const auto& G = curve.generator();
30	  sid2 = crypto::gen_random_bitlen(SEC_P_COM);
31	  sid = crypto::sha256_t::hash(sid1, sid2);
32	
33	  Q2 = x2 * G;
34	  pi_2.prove(Q2, x2, sid, 2);
35	}
