90	error_t key_share_2p_t::refresh(job_2p_t& job, const key_share_2p_t& key, key_share_2p_t& new_key) {
91	  error_t rv = UNINITIALIZED_ERROR;
92	  new_key.role = key.role;
93	  new_key.curve = key.curve;
94	  new_key.Q = key.Q;
95	
96	  const mod_t& q = key.curve.order();
97	  buf_t rand_bits;
98	  if (rv = agree_random(job, q.get_bits_count() + SEC_P_STAT, rand_bits)) return rv;
99	  bn_t r = bn_t::from_bin(rand_bits) % q;
100	
101	  if (job.is_p1()) {
102	    MODULO(q) { new_key.x_share = key.x_share + r; }
103	  }
104	
105	  if (job.is_p2()) {
106	    MODULO(q) { new_key.x_share = key.x_share - r; }
107	  }
108	
109	  return SUCCESS;
110	}
