475	error_t key_share_mp_t::reconstruct_additive_share(const mod_t& q, const node_t* node,
476	                                                   const std::set<crypto::pname_t>& quorum_names, bn_t& additive_share,
477	                                                   bool& is_satisfied) const {
478	  error_t rv = UNINITIALIZED_ERROR;
479	  int n = node->get_n();
480	
481	  switch (node->type) {
482	    case node_e::LEAF: {
483	      additive_share = 0;
484	      if (node->name == party_name) {
485	        additive_share = x_share;
486	      }
487	      is_satisfied = quorum_names.find(node->name) != quorum_names.end();
488	    } break;
489	
490	    case node_e::OR:
491	      additive_share = 0;
492	      is_satisfied = false;
493	      for (int i = 0; i < n; i++) {
494	        bn_t additive_share_from_child;
495	        bool child_is_satisfied = false;
496	        rv = reconstruct_additive_share(q, node->children[i], quorum_names, additive_share_from_child,
497	                                        child_is_satisfied);
498	        is_satisfied = is_satisfied || child_is_satisfied;
499	        if (rv == E_INSUFFICIENT) {
500	          rv = SUCCESS;
501	          continue;
502	        }
503	        if (rv) return rv;
504	        if (!child_is_satisfied) {
505	          continue;
506	        }
507	        additive_share = additive_share_from_child;
508	        break;
509	      }
510	      break;
511	    case node_e::AND:
512	      additive_share = 0;
513	      is_satisfied = true;
514	      for (int i = 0; i < n; i++) {
515	        bn_t additive_share_from_child;
516	        bool child_is_satisfied = false;
517	        rv = reconstruct_additive_share(q, node->children[i], quorum_names, additive_share_from_child,
518	                                        child_is_satisfied);
519	        is_satisfied = is_satisfied && child_is_satisfied;
520	        if (rv) {
521	          return rv;
522	        }
523	        if (additive_share_from_child != 0) {
524	          additive_share = additive_share_from_child;
525	        }
526	      }
527	      break;
528	
529	    case node_e::THRESHOLD: {
530	      std::vector<bn_t> interp_pids;
531	      interp_pids.reserve(node->threshold);
532	      bn_t share = 0;
533	      bn_t share_pid = 0;
534	      int satisfied_count = 0;
535	
536	      for (int i = 0; i < n; i++) {
537	        bn_t share_from_child;
538	        bool child_is_satisfied = false;
539	        rv = reconstruct_additive_share(q, node->children[i], quorum_names, share_from_child, child_is_satisfied);
540	        if (rv == E_INSUFFICIENT) {
541	          continue;
542	        }
543	        if (rv) return rv;
544	
545	        if (!child_is_satisfied) continue;
546	
547	        satisfied_count++;
548	        const bn_t child_pid = node->children[i]->get_pid();
549	        const bool child_is_selected = int(interp_pids.size()) < node->threshold;
550	        if (!child_is_selected) continue;
551	
552	        interp_pids.push_back(child_pid);
553	        if (share_from_child != 0) {
554	          share_pid = child_pid;
555	          share = share_from_child;
556	        }
557	      }
558	
559	      if (satisfied_count < node->threshold) {
560	        dylog_disable_scope_t dylog_disable_scope;
561	        return coinbase::error(E_INSUFFICIENT);
562	      }
563	      is_satisfied = true;
564	
565	      // Target party is outside the selected quorum subtree for this threshold node.
566	      if (share_pid == 0) {
567	        additive_share = 0;
568	        break;
569	      }
570	
571	      cb_assert(int(interp_pids.size()) == node->threshold);
572	
573	      additive_share = crypto::lagrange_partial_interpolate(0, {share}, {share_pid}, interp_pids, q);
574	    } break;
575	    case node_e::NONE: {
576	      return coinbase::error(E_CRYPTO, "key_share_mp_t::reconstruct_additive_share: none node");
577	    } break;
578	  }
579	
580	  return SUCCESS;
581	}
582	
583	error_t key_share_mp_t::reconstruct_pub_additive_shares(const crypto::ss::node_t* node,
584	                                                        const std::set<crypto::pname_t>& quorum_names,
585	                                                        const crypto::pname_t target, ecc_point_t& pub_additive_shares,
586	                                                        bool& is_satisfied) const {
587	  error_t rv = UNINITIALIZED_ERROR;
588	  int n = node->get_n();
589	
590	  switch (node->type) {
591	    case node_e::LEAF: {
592	      pub_additive_shares = curve.infinity();
593	      if (node->name == target) {
594	        pub_additive_shares = Qis.at(node->name);
595	      }
596	      is_satisfied = quorum_names.find(node->name) != quorum_names.end();
597	    } break;
598	
599	    case node_e::OR:
600	      pub_additive_shares = curve.infinity();
601	      is_satisfied = false;
602	      for (int i = 0; i < n; i++) {
603	        ecc_point_t additive_share_from_child = curve.infinity();
604	        bool child_is_satisfied = false;
605	        rv = reconstruct_pub_additive_shares(node->children[i], quorum_names, target, additive_share_from_child,
606	                                             child_is_satisfied);
607	        is_satisfied = is_satisfied || child_is_satisfied;
608	        if (rv == E_INSUFFICIENT) {
609	          rv = SUCCESS;
610	          continue;
611	        }
612	        if (rv) return rv;
613	        if (!child_is_satisfied) {
614	          continue;
615	        }
616	        pub_additive_shares = additive_share_from_child;
617	        break;
618	      }
619	      break;
620	    case node_e::AND:
621	      pub_additive_shares = curve.infinity();
622	      is_satisfied = true;
623	      for (int i = 0; i < n; i++) {
624	        ecc_point_t additive_share_from_child = curve.infinity();
625	        bool child_is_satisfied = false;
626	        rv = reconstruct_pub_additive_shares(node->children[i], quorum_names, target, additive_share_from_child,
627	                                             child_is_satisfied);
628	        is_satisfied = is_satisfied && child_is_satisfied;
629	        if (rv) {
630	          return rv;
631	        }
632	
633	        if (!additive_share_from_child.is_infinity()) {
634	          pub_additive_shares = additive_share_from_child;
635	        }
636	      }
637	      break;
638	
639	    case node_e::THRESHOLD: {
640	      std::vector<bn_t> interp_pids;
641	      interp_pids.reserve(node->threshold);
642	      ecc_point_t share = curve.infinity();
643	      bn_t share_pid = 0;
644	      int satisfied_count = 0;
645	
646	      for (int i = 0; i < n; i++) {
647	        ecc_point_t share_from_child = curve.infinity();
648	        bool child_is_satisfied = false;
649	        rv = reconstruct_pub_additive_shares(node->children[i], quorum_names, target, share_from_child,
650	                                             child_is_satisfied);
651	        if (rv == E_INSUFFICIENT) {
652	          continue;
653	        }
654	        if (rv) return rv;
655	
656	        if (!child_is_satisfied) continue;
657	
